contracts/AgriChain.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import { Ownable } from "@openzeppelin/contracts/access/Ownable.sol";
import { ReentrancyGuard } from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract AgriChain is Ownable, ReentrancyGuard {
    struct Crop {
        uint256 id;
        address farmer;
        uint256 price;
        uint256 quantity;
        uint256 expiry;
        bool isSold;
        address buyer;
        string offchainId;
    }

    uint256 public cropCount;
    mapping(uint256 => Crop) public crops;
    mapping(address => bool) public blacklisted;
    bool public paused;

    event CropListed(
        uint256 indexed cropId,
        address indexed farmer,
        uint256 price,
        uint256 quantity,
        uint256 expiry,
        string offchainId
    );
    event CropPurchased(uint256 indexed cropId, address indexed buyer, uint256 value);
    event ContractPaused(address indexed admin);
    event ContractUnpaused(address indexed admin);
    event WalletBlacklisted(address indexed wallet, bool status);

    modifier notPaused() {
        require(!paused, "Marketplace paused");
        _;
    }

    modifier notBlacklisted(address account) {
        require(!blacklisted[account], "Wallet blacklisted");
        _;
    }

    constructor(address admin) Ownable(admin) {}

    function pause() external onlyOwner {
        paused = true;
        emit ContractPaused(msg.sender);
    }

    function unpause() external onlyOwner {
        paused = false;
        emit ContractUnpaused(msg.sender);
    }

    function setBlacklist(address wallet, bool status) external onlyOwner {
        blacklisted[wallet] = status;
        emit WalletBlacklisted(wallet, status);
    }

    function listCrop(
        address farmer,
        uint256 price,
        uint256 quantity,
        uint256 expiry,
        string calldata offchainId
    ) external onlyOwner notPaused notBlacklisted(farmer) {
        require(expiry > block.timestamp, "Expiry must be future");
        require(price > 0, "Price required");
        require(quantity > 0, "Quantity required");

        cropCount += 1;
        crops[cropCount] = Crop({
            id: cropCount,
            farmer: farmer,
            price: price,
            quantity: quantity,
            expiry: expiry,
            isSold: false,
            buyer: address(0),
            offchainId: offchainId
        });

        emit CropListed(cropCount, farmer, price, quantity, expiry, offchainId);
    }

    function purchaseCrop(uint256 cropId)
        external
        payable
        nonReentrant
        notPaused
        notBlacklisted(msg.sender)
    {
        Crop storage crop = crops[cropId];
        require(crop.id != 0, "Crop not found");
        require(!crop.isSold, "Already sold");
        require(crop.expiry > block.timestamp, "Crop expired");
        require(msg.value == crop.price, "Incorrect payment");
        require(!blacklisted[crop.farmer], "Farmer blacklisted");

        crop.isSold = true;
        crop.buyer = msg.sender;

        (bool success, ) = crop.farmer.call{ value: msg.value }("");
        require(success, "Payment failed");

        emit CropPurchased(cropId, msg.sender, msg.value);
    }
}

